# Auto-generated skill tree location data for Salt and Sanctuary APWorld
from typing import Dict, NamedTuple, List

SKILLTREE_BASE_ID = 283670000

class SkillTreeLocationData(NamedTuple):
    code: int
    node_id: int
    depth: int
    cost: int
    parents: List[int]
    is_root: bool

# Track how many of each skill type we've seen for unique naming
_skill_counters: Dict[str, int] = {}

def _get_location_name(skill_name: str, depth: int, node_id: int) -> str:
    """Generate a unique location name with simple counter."""
    # Class nodes already have unique names
    if skill_name.startswith("Class "):
        return f"Skill Tree - {skill_name}"
    
    # For stat nodes, use a simple counter to make unique names
    if skill_name not in _skill_counters:
        _skill_counters[skill_name] = 0
    
    _skill_counters[skill_name] += 1
    count = _skill_counters[skill_name]
    
    return f"Skill Tree - {skill_name} #{count} (Depth {depth})"

