# Build the locations dictionary with improved names
skilltree_locations: Dict[str, SkillTreeLocationData] = {}

for node_id, skill_name, depth, cost, p1, p2, is_root in _raw_data:
    name = _get_location_name(skill_name, depth, node_id)
    skilltree_locations[name] = SkillTreeLocationData(
        code=SKILLTREE_BASE_ID + node_id,
        node_id=node_id,
        depth=depth,
        cost=cost,
        parents=[p1, p2],
        is_root=is_root
    )

# Max depth for progression item placement (brands/keys)
SKILLTREE_PROGRESSION_MAX_DEPTH = 8

# Locations at each depth (for logic)
SKILLTREE_BY_DEPTH: Dict[int, List[str]] = {}
for name, data in skilltree_locations.items():
    if data.depth not in SKILLTREE_BY_DEPTH:
        SKILLTREE_BY_DEPTH[data.depth] = []
    SKILLTREE_BY_DEPTH[data.depth].append(name)
